INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00443', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲主張乙（住所地為A地）向伊借款新臺幣（下同）1,000萬元，並簽立借貸契約書（下稱系爭契約）， 約定以乙所有坐落B地之房地（下稱系爭房地）作擔保，若乙屆期不能償還本利時，願將該房地移轉 予甲。甲於C地將借款現金1,000萬元交付予乙，嗣乙亦在C地償還甲100萬元。惟乙就其餘借款屆 期無法清償，且將系爭房地移轉予第三人等情，爰依系爭契約法律關係，起訴請求乙賠償以系爭房地 現值計算之1,500萬元。關於本件訴訟管轄權，下列敘述何者正確？', '["因乙住所地為A地，甲得向A地之法院起訴", "因系爭房地坐落B地，甲得向B地之法院起訴", "因甲於C地將借款現金1,000萬元交付予乙，乙亦在C地償還甲100萬元，甲得向C地之法院起訴", "因以坐落B地之系爭房地擔保債權而涉訟，甲應向B地之法院起訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00444', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者，具當事人適格？', '["甲起訴請求丙塗銷乙、丙間就A不動產之所有權移轉登記，僅以乙為被告", "甲起訴請求撤銷乙、丙間之詐害行為，僅以乙為被告", "甲起訴請求確認乙、丙間為父子關係存在，僅以丙為被告，未列尚生存之乙為被告", "甲為A不動產之共有人，其為共有人全體之利益，起訴請求占有A不動產之乙返還A不動產予全 體共有人，僅以甲為原告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00445', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲僱用之職員乙於執行職務時侵害丙之權利，丙對乙訴請損害賠償，下列敘述何者正確？', '["甲可以為輔助乙而參加該訴訟", "甲必須於第一審參加訴訟，方有可能於乙敗訴時，為乙提起上訴", "甲可以於第一審進行言詞辯論時，以言詞表明參加訴訟，由書記官記明筆錄", "甲輔助乙所為之訴訟行為，若與乙之行為牴觸者，以對乙有利益為限，發生訴訟上之效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00446', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '已成年之甲因乙酒駕闖紅燈，發生車禍受傷成為植物人，未經監護宣告，如欲向乙請求因侵權行為所 致之損害，則甲之親屬應請求指定何種代理人？', '["法定代理人", "特別代理人", "訴訟代理人", "輔佐人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00447', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於法院得依供擔保人之聲請，以裁定命返還其提存物之原因，下列敘述何者錯誤？', '["訴訟終結後，供擔保人證明已定20日以上之期間，催告受擔保利益人行使權利而未行使", "供擔保人證明受擔保利益人同意返還", "應供擔保之原因消滅", "受擔保利益人死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00448', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者，非屬不變期間？', '["上訴期間", "和解成立後，聲請退還所繳裁判費三分之二之期間", "抗告期間", "提起再審訴訟之期間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00449', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟程序當然停止，下列敘述何者正確？', '["當事人之法定代理人死亡者，訴訟程序在該法定代理人之全體繼承人共同聲明訴之變更前，當然 停止", "法人因合併而消滅者，訴訟程序在合併後存續之法人，向法院陳報其合併後法人之全數財產報告前， 當然停止", "當事人死亡者，訴訟程序在遺產管理人向法院陳報遺產分配方式前，當然停止", "當事人喪失訴訟能力，訴訟程序在有法定代理人承受其訴訟前，當然停止"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00450', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於判決之更正，下列敘述何者正確？', '["判決如有誤算被告應給付原告損害賠償金額之錯誤者，法院均得依職權更正，並通知兩造之訴訟代 理人", "判決如就系爭土地地號之記載錯誤，法院得不待裁定，逕依職權通知地政機關更正", "判決如有誤寫、誤算或其他類此之顯然錯誤者，法院得依聲請或依職權以裁定更正", "第二審判決主文如有誤寫或誤算之顯然錯誤者，當事人得上訴第三審，請求救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00451', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲向管轄之地方法院指定乙為送達代收人，對於甲之送達，何時發生效力？', '["向乙送達時，發生送達之效力", "乙轉交予甲時，始發生送達之效力", "如逕送達甲，經甲收受，仍不發生送達之效力", "如甲因敗訴上訴到第二審法院，第二審法院仍向乙送達，除甲向法院再行遞交委任狀外，對甲不生 送達之效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00452', 'judicial-57f41407', 'judicial-57f41407-moex-112-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '於通常訴訟程序之第一次言詞辯論期日，一造當事人經合法通知而無正當理由不到場時，法院如何 處理？', '["得依到場當事人之聲請，由其一造辯論而為判決", "得依職權由到場之當事人辯論後而為判決", "得為該當事人敗訴之缺席判決", "得裁定停止訴訟程序"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:39+00:00", "source_pdf_sha1": "3d06ebd3dac6", "answer_pdf_sha1": "a08edc8cf0cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
